    28→enum nfp_relo_type {
    29→	RELO_NONE = 0,
    30→	/* standard internal jumps */
    31→	RELO_BR_REL,
    32→	/* internal jumps to parts of the outro */
    33→	RELO_BR_GO_OUT,
    34→	RELO_BR_GO_ABORT,
    35→	RELO_BR_GO_CALL_PUSH_REGS,
    36→	RELO_BR_GO_CALL_POP_REGS,
