   153→		int guaranteed_sub;
   154→		int guaranteed_add;
   155→	} adjust_head;
   156→
   157→	struct {
   158→		u32 types;
   159→		u32 max_maps;
   160→		u32 max_elems;
   161→		u32 max_key_sz;
   162→		u32 max_val_sz;
   163→		u32 max_elem_sz;
   164→	} maps;
   165→
   166→	struct {
   167→		u32 map_lookup;
   168→		u32 map_update;
   169→		u32 map_delete;
   170→		u32 perf_event_output;
   171→	} helpers;
   172→
   173→	bool pseudo_random;
